public class Main {
  public static void main(String[] args) {
    int x = 10;

    if (x > 0) {
      System.out.println("Positive");
    } else if (x == 0) {
      System.out.println("Zero");
    } else {
      System.out.println("Negative");
    }

    String color = "red";
    if ("red".equals(color)) {
      System.out.println("It is red");
    }
  }
}

